/**
 * Pure converter functions that transform abstract card data into ItemCard/ItemListElement props.
 * These replace the transformation logic previously embedded in each type-specific card wrapper component.
 * The wrapper components (HardwareCard, SoftwareCard, etc.) are now thin shims that call these functions.
 *
 * Benefits:
 * - Logic is testable without React rendering
 * - Call sites can spread and override individual props after conversion
 * - Single source of truth for each content type's card representation
 */
import React from "react";
import { Calendar, MapPoint } from "@solar-icons/react-perf/LineDuotone";
import { parseDateLocal, getFormattedDateRanges } from "./date-utils.js";
import { getLocationString } from "./event-utils.js";
import { resolveCardImagePolicy, resolveLogoAsset, resolveImagePolicy, } from "./images.js";
function capitalize(value) {
    if (!value)
        return "";
    return value.charAt(0).toUpperCase() + value.slice(1);
}
export function toHardwareCardProps(id, data) {
    const cardImages = resolveCardImagePolicy({
        hero: data.images?.hero,
        logoOrAvatar: resolveLogoAsset(data.images),
        policy: data.imagePolicy,
    });
    return {
        title: data.name || id,
        description: data.shortDescription || data.description,
        href: `/hardware/${id}`,
        type: "hardware",
        image: cardImages.image,
        imageAlt: data.name,
        logo: cardImages.logo,
        showFallbackAvatar: cardImages.showFallbackIcon,
        logoBackdrop: cardImages.logoBackdrop,
        status: data.status,
        category: capitalize(data.category),
        featuredState: data.featured ? "featured" : "not-featured",
        links: {
            website: data.links?.website,
            github: data.links?.github || data.links?.code,
            docs: data.links?.documentation,
            demo: data.links?.demo,
        },
    };
}
export function toSoftwareCardProps(id, data) {
    const cardImages = resolveCardImagePolicy({
        hero: data.images?.hero,
        logoOrAvatar: resolveLogoAsset(data.images),
        policy: data.imagePolicy,
    });
    return {
        title: data.name || id,
        description: data.shortDescription || data.description,
        href: `/software/${id}`,
        type: "software",
        image: cardImages.image,
        imageAlt: data.name,
        logo: cardImages.logo,
        showFallbackAvatar: cardImages.showFallbackIcon,
        logoBackdrop: cardImages.logoBackdrop,
        status: data.status,
        category: capitalize(data.category),
        featuredState: data.featured ? "featured" : "not-featured",
        links: {
            website: data.links?.website,
            github: data.links?.github || data.links?.code,
            docs: data.links?.documentation,
            demo: data.links?.demo,
            pypi: data.links?.pypi,
            npm: data.links?.npm,
        },
    };
}
export function toEventCardProps(id, data, now = new Date()) {
    const startDate = parseDateLocal(data.startDate);
    const endDate = data.endDate ? parseDateLocal(data.endDate) : startDate;
    let status = "upcoming";
    if (now >= startDate && now <= endDate) {
        status = "happening now";
    }
    else if (now > endDate) {
        status = "past";
    }
    const featuredState = status === "past" && data.featured
        ? "previously-featured"
        : data.featured
            ? "featured"
            : "not-featured";
    const cardImages = resolveCardImagePolicy({
        hero: data.images?.hero,
        logoOrAvatar: resolveLogoAsset(data.images),
        policy: data.imagePolicy,
    });
    return {
        title: data.displayName || data.name || id,
        listItems: [
            {
                text: getFormattedDateRanges(startDate, endDate),
                icon: React.createElement(Calendar, {
                    className: "text-accent-two mt-0.5 w-4 h-4 shrink-0",
                }),
            },
            {
                text: getLocationString(data.location) ?? "Unknown Location",
                icon: React.createElement(MapPoint, {
                    className: "text-accent-two mt-0.5 w-4 h-4 shrink-0",
                }),
            },
        ],
        href: `/events/${id}`,
        type: "events",
        image: cardImages.image,
        imageAlt: data.name,
        logo: cardImages.logo,
        showFallbackAvatar: cardImages.showFallbackIcon,
        logoBackdrop: cardImages.logoBackdrop,
        status,
        category: capitalize(data.type),
        featuredState,
        links: {
            website: data.links?.website,
            registration: data.links?.registration,
        },
    };
}
export function toResearchCardProps(id, data) {
    const publishDate = data.publishDate ? new Date(data.publishDate) : undefined;
    const yearLabel = publishDate && !Number.isNaN(publishDate.getTime())
        ? publishDate.getFullYear()
        : data.year;
    const category = [capitalize(data.type), yearLabel].filter(Boolean).join(" • ");
    const docsLink = data.links?.paper ||
        data.links?.documentation ||
        data.links?.pdf ||
        data.links?.proceedings ||
        (data.links?.doi ? `https://doi.org/${data.links.doi}` : undefined) ||
        (data.links?.arxiv ? `https://arxiv.org/abs/${data.links.arxiv}` : undefined);
    const cardImages = resolveCardImagePolicy({
        hero: data.images?.hero,
        logoOrAvatar: resolveLogoAsset(data.images),
        policy: data.imagePolicy,
    });
    return {
        title: data.title || id,
        description: data.description,
        href: `/research/${id}`,
        type: "research",
        image: cardImages.image,
        imageAlt: data.title,
        logo: cardImages.logo,
        showFallbackAvatar: cardImages.showFallbackIcon,
        logoBackdrop: cardImages.logoBackdrop,
        category,
        featuredState: data.featured ? "featured" : "not-featured",
        links: {
            website: data.links?.website || data.links?.program,
            github: data.links?.code || data.links?.github,
            demo: data.links?.demo || data.links?.video,
            docs: docsLink,
        },
    };
}
export function toPersonCardProps(id, data) {
    const description = data.bio ||
        (data.expertise && data.expertise.length > 0
            ? `Expertise: ${data.expertise.slice(0, 3).join(", ")}`
            : undefined);
    const cardImages = resolveCardImagePolicy({
        hero: data.images?.hero,
        logoOrAvatar: data.images?.avatar,
        policy: data.imagePolicy,
    });
    return {
        title: data.name || id,
        description,
        href: `/people/${id}`,
        type: "people",
        logo: cardImages.logo,
        image: cardImages.image,
        showFallbackAvatar: cardImages.showFallbackIcon,
        logoBackdrop: cardImages.logoBackdrop,
        category: data.title,
        featuredState: data.featured ? "featured" : "not-featured",
        links: {
            website: data.links?.website,
            github: data.links?.github
                ? `https://github.com/${data.links.github}`
                : undefined,
        },
    };
}
