export function toPersonListElementProps(id, data, affiliationLabel) {
    const fullName = (data.honorific ? `${data.honorific} ${data.name}` : data.name) || id;
    const currentAffiliation = data.affiliations?.find((aff) => aff.isPrimary) ??
        data.affiliations?.find((aff) => !aff.endDate);
    const affiliation = affiliationLabel || currentAffiliation?.organizationId;
    const parts = [affiliation, data.title].filter(Boolean);
    const description = parts.length ? parts.join(" · ") : undefined;
    const imagePolicy = resolveImagePolicy(data.imagePolicy);
    return {
        title: fullName,
        description,
        href: `/people/${id}`,
        type: "people",
        logo: data.images?.avatar,
        imageAlt: fullName,
        logoBackdrop: imagePolicy.logoOrAvatarBackdropInList,
        featuredState: data.featured ? "featured" : "not-featured",
    };
}
export function toOrganizationListElementProps(id, data, roleLabel) {
    const title = data?.shortName || data?.name || id;
    const location = data?.location?.city || data?.location?.country
        ? [data?.location?.city, data?.location?.country]
            .filter(Boolean)
            .join(", ")
        : undefined;
    const parts = [roleLabel, location].filter(Boolean);
    const description = parts.length > 0 ? parts.join(" · ") : data?.description;
    const imagePolicy = resolveImagePolicy(data?.imagePolicy);
    return {
        title,
        description,
        href: `/organizations/${id}`,
        type: "organizations",
        logo: resolveLogoAsset(data?.images),
        imageAlt: title,
        logoBackdrop: imagePolicy.logoOrAvatarBackdropInList,
        featuredState: data?.featured ? "featured" : "not-featured",
    };
}
