// Status labels for display
export const STATUS_LABELS = {
    // Hardware
    available: "Available",
    "in-progress": "In Progress",
    "coming-soon": "Coming Soon",
    // Software
    stable: "Stable",
    beta: "Beta",
    alpha: "Alpha",
    // Events
    upcoming: "Upcoming",
    ongoing: "Happening Now",
    past: "Past Event",
    // Shared
    deprecated: "Deprecated",
};
export function getStatusColor(status, colorType = "text") {
    if (!status || !(status in STATUS_COLORS)) {
        return colorType === "chip"
            ? "gray"
            : "text-neutral-600 dark:text-neutral-400";
    }
    const statusConfig = STATUS_COLORS[status];
    switch (colorType) {
        case "text":
            return statusConfig.text;
        case "bg":
            return statusConfig.bg;
        case "bullet":
            return statusConfig.bullet;
        case "border":
            return statusConfig.border;
        case "chip":
            return statusConfig.chip;
        default:
            return statusConfig.text;
    }
}
export function getStatusLabel(status) {
    if (!status || !(status in STATUS_LABELS)) {
        return status || "";
    }
    return STATUS_LABELS[status];
}
export const CATEGORY_LABELS = {
    hardware: {
        mobile: "Mobile Robot",
        social: "Social Robot",
        assistive: "Assistive Robot",
        research: "Research Platform",
        educational: "Educational Robot",
    },
    software: {
        framework: "Framework",
        library: "Library",
        tool: "Tool",
        simulation: "Simulation",
        dataset: "Dataset",
        model: "Model",
    },
};
export function getCategoryLabel(type, category) {
    if (!category || !CATEGORY_LABELS[type]) {
        return category || "";
    }
    const labels = CATEGORY_LABELS[type];
    if (category in labels) {
        return labels[category];
    }
    return category;
}
