export const getLocationString = (location) => {
    if (!location)
        return undefined;
    if (location.city && location.country) {
        return `${location.city}, ${location.country}`;
    }
    if (location.country) {
        return location.country;
    }
    if (location.online) {
        return "Online";
    }
    return undefined;
};
export const getEventPreviewDescription = (dateString, descriptionString, locationString) => {
    if (locationString) {
        return `${dateString} • ${locationString}`;
    }
    if (descriptionString) {
        return `${dateString} • ${descriptionString}`;
    }
    return dateString;
};
