export const parseDateLocal = (value) => {
    if (value instanceof Date) {
        return new Date(value.getUTCFullYear(), value.getUTCMonth(), value.getUTCDate());
    }
    if (value === undefined || value === null) {
        return new Date(NaN);
    }
    if (typeof value === "number") {
        return new Date(value);
    }
    const stringValue = String(value);
    const isoMatch = stringValue.match(/^(\d{4})-(\d{2})-(\d{2})/);
    if (isoMatch) {
        const [, year, month, day] = isoMatch;
        return new Date(Number(year), Number(month) - 1, Number(day));
    }
    return new Date(stringValue);
};
const NARROW_SPACE_REGEX = /[\u202F\u00A0\u2009]/g;
const EN_DASH_SPACING_REGEX = /\s*–\s*/g;
function normalizeWhitespace(value) {
    return value
        .replace(NARROW_SPACE_REGEX, " ")
        .replace(EN_DASH_SPACING_REGEX, " – ");
}
function formatDateWithParts(date, locale, options) {
    const formatter = new Intl.DateTimeFormat(locale, options);
    return normalizeWhitespace(formatter.format(date));
}
function formatDateRangeWithParts(startDate, endDate, locale, options) {
    const formatter = new Intl.DateTimeFormat(locale, options);
    if (typeof formatter.formatRange === "function") {
        return normalizeWhitespace(formatter.formatRange(startDate, endDate));
    }
    const start = formatDateWithParts(startDate, locale, options);
    const end = formatDateWithParts(endDate, locale, options);
    return start === end ? start : `${start} – ${end}`;
}
export function getFormattedDateRanges(date1, date2, locale = "en-US", options = { year: "numeric", month: "short", day: "numeric" }) {
    if (!date2 || date1.getTime() === date2.getTime()) {
        return formatDateWithParts(date1, locale, options);
    }
    return formatDateRangeWithParts(date1, date2, locale, options);
}
